  1→"use client";
  2→
  3→import { useState, useMemo } from "react";
  4→import { useAccount, useWriteContract, useSwitchChain } from "wagmi";
  5→import { celo } from "viem/chains";
  6→import { SelfVerification } from "@/components/self-verification";
  7→import { LendingDashboard } from "@/components/lending-dashboard";
  8→import { AgentMetadataForm } from "@/components/agent-metadata-form";
  9→import dynamic from "next/dynamic";
 10→import type { WidgetConfig } from "@lifi/widget";
 11→
 12→const LiFiWidget = dynamic(
 13→  () => import("@lifi/widget").then((m) => m.LiFiWidget),
 14→  { ssr: false }
 15→);
 16→
 17→// USDC on Celo
 18→const CELO_USDC = "0xcebA9300f2b948710d2653dD7B07f33A8B32118C";
 19→
 20→// Self Agent Registry (ERC-8004) on Celo mainnet
 21→const REGISTRY_ADDRESS =
 22→  "0x62E37d0f6c5f67784b8828B3dF68BCDbB2e55095" as const;
 23→
 24→const REGISTRY_ABI = [
 25→  {
 26→    name: "setAgentWallet",
 27→    type: "function",
 28→    stateMutability: "nonpayable",
 29→    inputs: [
 30→      { name: "agentId", type: "uint256" },
 31→      { name: "newWallet", type: "address" },
 32→      { name: "deadline", type: "uint256" },
 33→      { name: "signature", type: "bytes" },
 34→    ],
 35→    outputs: [],
 36→  },
 37→] as const;
 38→
 39→const STEPS = [
 40→  { id: "deploy", label: "Deploy Agent" },
 41→  { id: "verify", label: "Verify Identity" },
 42→  { id: "metadata", label: "Set Metadata" },
 43→  { id: "delegate", label: "Delegate" },
 44→  { id: "monitor", label: "Monitor" },
 45→] as const;
 46→
 47→type Step = (typeof STEPS)[number]["id"];
 48→
 49→const labelClass =
 50→  "font-mono text-xs uppercase tracking-[0.15em] text-ink-lighter";
 51→const inputClass =
 52→  "w-full border-b border-cream-dark bg-transparent px-0 py-2 text-sm text-ink placeholder:text-ink-lighter focus:border-ink focus:outline-none";
 53→
 54→export function DeployAgent() {
 55→  const { address } = useAccount();
 56→  const { writeContractAsync } = useWriteContract();
 57→  const { switchChainAsync } = useSwitchChain();
 58→  const [step, setStep] = useState<Step>("deploy");
 59→  const [isVerified, setIsVerified] = useState(false);
 60→  const [isDelegated, setIsDelegated] = useState(false);
 61→  const [agentAddress, setAgentAddress] = useState<string | null>(null);
 62→  const [walletId, setWalletId] = useState<string | null>(null);
 63→  const [agentId, setAgentId] = useState<number | null>(null);
 64→  const [serviceId, setServiceId] = useState<string | null>(null);
 65→  const [environmentId, setEnvironmentId] = useState<string | null>(null);
 66→  const [deploying, setDeploying] = useState(false);
 67→  const [delegating, setDelegating] = useState(false);
 68→  const [agentName, setAgentName] = useState("");
 69→  const [deployError, setDeployError] = useState<string | null>(null);
 70→  const [showFundWidget, setShowFundWidget] = useState(false);
 71→
 72→  // LI.FI widget config — fixed destination: USDC on Celo to agent wallet
 73→  const lifiConfig: WidgetConfig = useMemo(
 74→    () => ({
 75→      integrator: "openclaw-lending",
 76→      toChain: 42220,
 77→      toToken: CELO_USDC,
 78→      toAddress: {
 79→        address: agentAddress || "",
 80→        chainType: "EVM" as any,
 81→      },
 82→      // Lock destination: only Celo allowed as target chain, only USDC as target token
 83→      chains: {
 84→        to: { allow: [42220] },
 85→      },
 86→      tokens: {
 87→        to: {
 88→          allow: [{ chainId: 42220, address: CELO_USDC }],
 89→        },
 90→      },
 91→      hiddenUI: ["toAddress", "toToken"],
 92→      theme: {
 93→        container: {
 94→          border: "1px solid rgb(220, 215, 206)",
 95→          borderRadius: "0px",
 96→        },
 97→      },
 98→    }),
 99→    [agentAddress]
100→  );
101→
102→  const handleDeploy = async () => {
103→    if (!agentName.trim()) return;
104→    setDeploying(true);
105→    setDeployError(null);
106→    try {
107→      const res = await fetch("/api/agent/deploy", {
108→        method: "POST",
109→        headers: { "Content-Type": "application/json" },
110→        body: JSON.stringify({ agentName: agentName.trim() }),
111→      });
112→      const data = await res.json();
113→      if (data.error) {
114→        if (data.error.includes("already exists")) {
115→          setDeployError(
116→            `Name "${agentName.trim()}" is taken — try a different name.`
117→          );
118→        } else {
119→          setDeployError(data.error);
120→        }
121→        return;
122→      }
123→
124→      setWalletId(data.walletId);
125→      setServiceId(data.serviceId);
126→      setEnvironmentId(data.environmentId);
127→      setAgentAddress(data.walletAddress);
128→      setStep("verify");
129→    } catch (err) {
130→      const msg = err instanceof Error ? err.message : "Deploy failed";
131→      setDeployError(msg);
132→    } finally {
133→      setDeploying(false);
134→    }
135→  };
136→
137→  const handleVerificationSuccess = (
138→    _agentAddr: string,
139→    selfAgentId?: number
140→  ) => {
141→    setIsVerified(true);
142→    if (selfAgentId != null) {
143→      setAgentId(selfAgentId);
144→    }
145→    setStep("metadata");
146→  };
147→
148→  const handleMetadataSuccess = () => {
149→    setStep("delegate");
150→  };
151→
152→  const handleDelegate = async () => {
153→    if (!address || agentId == null || !walletId || !agentAddress) return;
154→    setDelegating(true);
155→    try {
156→      const res = await fetch("/api/agent-id/delegate", {
157→        method: "POST",
158→        headers: { "Content-Type": "application/json" },
159→        body: JSON.stringify({
160→          agentId,
161→          walletId,
162→          walletAddress: agentAddress,
163→          ownerAddress: address,
164→        }),
165→      });
166→      const data = await res.json();
167→      if (data.error) throw new Error(data.error);
168→
169→      // Ensure wallet is on Celo
170→      await switchChainAsync({ chainId: celo.id });
171→      await writeContractAsync({
172→        address: REGISTRY_ADDRESS,
173→        abi: REGISTRY_ABI,
174→        functionName: "setAgentWallet",
175→        chainId: celo.id,
176→        args: [
177→          BigInt(agentId),
178→          data.newWallet as `0x${string}`,
179→          BigInt(data.deadline),
180→          data.signature as `0x${string}`,
181→        ],
182→      });
183→
184→      if (serviceId && environmentId) {
185→        await fetch("/api/agent/set-env", {
186→          method: "POST",
187→          headers: { "Content-Type": "application/json" },
188→          body: JSON.stringify({
189→            serviceId,
190→            environmentId,
191→            vars: { SELF_AGENT_ID: String(agentId) },
192→          }),
193→        });
194→      }
195→
196→      setIsDelegated(true);
197→      setStep("monitor");
198→    } catch (err) {
199→      console.error("Delegation failed:", err);
200→    } finally {
201→      setDelegating(false);
202→    }
203→  };
204→
205→  const currentIdx = STEPS.findIndex((x) => x.id === step);
206→
207→  if (!address) {
208→    return (
209→      <div className="mx-auto max-w-md text-center">
210→        <h3 className="font-serif text-2xl text-ink">Connect your wallet.</h3>
211→        <p className="mt-4 text-sm leading-relaxed text-ink-light">
212→          Connect your wallet to deploy your autonomous agent and access
213→          on-chain lending on Celo.
214→        </p>
215→      </div>
216→    );
217→  }
218→
219→  return (
220→    <div className="space-y-12">
221→      {/* Agent info bar */}
222→      {agentAddress && (
223→        <div className="flex items-center justify-between border-b border-cream-dark pb-4">
224→          <div>
225→            <span className={labelClass}>Agent Wallet</span>
226→            <button
227→              onClick={() => navigator.clipboard.writeText(agentAddress)}
228→              title="Copy to clipboard"
229→              className="mt-1 flex items-center gap-1.5 font-mono text-sm text-ink hover:text-ink-light transition-colors cursor-pointer"
230→            >
231→              {agentAddress.slice(0, 6)}...{agentAddress.slice(-4)}
232→              <svg xmlns="http://www.w3.org/2000/svg" width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><rect width="14" height="14" x="8" y="8" rx="2"/><path d="M4 16c-1.1 0-2-.9-2-2V4c0-1.1.9-2 2-2h10c1.1 0 2 .9 2 2"/></svg>
233→            </button>
234→          </div>
235→          <div>
236→            <span className={labelClass}>Network</span>
237→            <p className="mt-1 font-mono text-sm text-ink">Celo</p>
238→          </div>
239→          <div>
240→            <span className={labelClass}>Identity</span>
241→            <p className="mt-1 font-mono text-sm text-ink">
242→              {isDelegated
243→                ? "Self (8004 SBT) — Delegated"
244→                : isVerified
245→                  ? "Self (8004 SBT)"
246→                  : "Not verified"}
247→            </p>
248→          </div>
249→        </div>
250→      )}
251→
252→      {/* Step indicator */}
253→      <div className="flex items-center gap-3">
254→        {STEPS.map((s, i) => {
255→          const isDone = currentIdx > i;
256→          const isCurrent = step === s.id;
257→          return (
258→            <div key={s.id} className="flex items-center gap-3">
259→              <div className="flex items-center gap-2">
260→                <span
261→                  className={`font-mono text-xs ${isCurrent ? "text-ink" : isDone ? "text-ink-light" : "text-ink-lighter"}`}
262→                >
263→                  {isDone ? "\u2713" : `0${i + 1}`}
264→                </span>
265→                <button
266→                  onClick={() => {
267→                    if (isDone || isCurrent) setStep(s.id);
268→                  }}
269→                  disabled={!isDone && !isCurrent}
270→                  className={`font-mono text-xs uppercase tracking-wider ${isCurrent ? "text-ink" : isDone ? "text-ink-light cursor-pointer hover:text-ink" : "text-ink-lighter"}`}
271→                >
272→                  {s.label}
273→                </button>
274→              </div>
275→              {i < STEPS.length - 1 && (
276→                <div className="h-px w-12 bg-cream-dark" />
277→              )}
278→            </div>
279→          );
280→        })}
281→      </div>
282→
283→      {/* Step 1: Deploy Agent */}
284→      {step === "deploy" && (
285→        <div className="mx-auto max-w-md">
286→          <h3 className="font-serif text-xl text-ink">Deploy your agent</h3>
287→          <p className="mt-2 text-sm text-ink-light">
288→            Deploy a Dockerized OpenClaw agent instance. Your connected wallet
289→            serves as the human anchor for the agent lifecycle.
290→          </p>
291→
292→          <div className="mt-6 space-y-4">
293→            <div>
294→              <label className={labelClass}>Agent Name</label>
295→              <input
296→                type="text"
297→                value={agentName}
298→                onChange={(e) => setAgentName(e.target.value)}
299→                placeholder="my-agent"
300→                className={inputClass}
301→              />
302→            </div>
303→
304→            <button
305→              onClick={handleDeploy}
306→              disabled={deploying || !agentName.trim()}
307→              className="w-full bg-ink px-8 py-4 font-mono text-sm uppercase tracking-wider text-cream transition-opacity hover:opacity-80 disabled:opacity-30"
308→            >
309→              {deploying ? "Deploying..." : "Deploy Agent"}
310→            </button>
311→
312→            {deployError && (
313→              <div className="mt-4 rounded border border-red-200 bg-red-50 px-4 py-3 text-sm text-red-800">
314→                {deployError}
315→              </div>
316→            )}
317→          </div>
318→
319→          <p className="mt-4 text-xs text-ink-lighter">
320→            Human wallet: {address.slice(0, 6)}...{address.slice(-4)}
321→          </p>
322→        </div>
323→      )}
324→
325→      {/* Step 2: Verify Identity */}
326→      {step === "verify" && (
327→        <div className="mx-auto max-w-md">
328→          <SelfVerification
329→            walletAddress={address}
330→            onSuccess={handleVerificationSuccess}
331→          />
332→
333→          <div className="mt-8 border-t border-cream-dark pt-6">
334→            <button
335→              onClick={() => setStep("monitor")}
336→              className="font-mono text-xs text-ink-lighter hover:text-ink"
337→            >
338→              Skip verification (agent cannot borrow without 8004 SBT)
339→            </button>
340→          </div>
341→        </div>
342→      )}
343→
344→      {/* Step 3: Set Metadata */}
345→      {step === "metadata" && agentId != null && (
346→        <div>
347→          <AgentMetadataForm
348→            agentId={agentId}
349→            agentName={agentName || "OpenClaw Lending Agent"}
350→            onSuccess={handleMetadataSuccess}
351→          />
352→          <div className="mx-auto mt-6 max-w-md border-t border-cream-dark pt-4">
353→            <button
354→              onClick={() => setStep("delegate")}
355→              className="font-mono text-xs text-ink-lighter hover:text-ink"
356→            >
357→              Skip metadata (can be set later)
358→            </button>
359→          </div>
360→        </div>
361→      )}
362→
363→      {/* Step 4: Delegate Identity to Agent Wallet */}
364→      {step === "delegate" && (
365→        <div className="mx-auto max-w-md">
366→          <h3 className="font-serif text-xl text-ink">
367→            Delegate identity to agent
368→          </h3>
369→          <p className="mt-2 text-sm text-ink-light">
370→            Link your Self-verified identity (Agent ID #{agentId}) to your
371→            agent&apos;s wallet. This calls{" "}
372→            <span className="font-mono">setAgentWallet</span> on the Self
373→            registry so the agent can prove it&apos;s human-backed on-chain.
374→          </p>
375→
376→          <div className="mt-6 space-y-4">
377→            <div className="space-y-3 rounded border border-cream-dark bg-cream px-4 py-3">
378→              <div className="flex justify-between font-mono text-sm">
379→                <span className="text-ink-lighter">Self Agent ID</span>
380→                <span className="text-ink">#{agentId}</span>
381→              </div>
382→              <div className="flex justify-between font-mono text-sm">
383→                <span className="text-ink-lighter">Agent Wallet (7702)</span>
384→                <span className="text-ink">
385→                  {agentAddress
386→                    ? `${agentAddress.slice(0, 6)}...${agentAddress.slice(-4)}`
387→                    : "—"}
388→                </span>
389→              </div>
390→            </div>
391→
392→            <button
393→              onClick={handleDelegate}
394→              disabled={delegating || agentId == null}
395→              className="w-full bg-ink px-8 py-4 font-mono text-sm uppercase tracking-wider text-cream transition-opacity hover:opacity-80 disabled:opacity-30"
396→            >
397→              {delegating ? "Delegating..." : "Delegate Identity"}
398→            </button>
399→          </div>
400→
401→          <p className="mt-4 text-xs text-ink-lighter">
402→            This transaction is sent from your human wallet and requires one
403→            on-chain confirmation.
404→          </p>
405→        </div>
406→      )}
407→
408→      {/* Step 5: Monitor + Fund */}
409→      {step === "monitor" && agentAddress && (
410→        <>
411→          {/* Fund agent section — always visible at top */}
412→          <div>
413→            <div className="flex items-center justify-between">
414→              <div>
415→                <h3 className="font-serif text-xl text-ink">
416→                  Fund your agent
417→                </h3>
418→                <p className="mt-1 text-sm text-ink-light">
419→                  Send USDC from any chain to your agent wallet on Celo.
420→                </p>
421→              </div>
422→              <button
423→                onClick={() => setShowFundWidget(!showFundWidget)}
424→                className="border border-cream-dark px-6 py-3 font-mono text-sm uppercase tracking-wider text-ink transition-colors hover:border-ink"
425→              >
426→                {showFundWidget ? "Hide" : "Fund Agent"}
427→              </button>
428→            </div>
429→
430→            {showFundWidget && (
431→              <div className="mt-6">
432→                <LiFiWidget {...lifiConfig} />
433→              </div>
434→            )}
435→          </div>
436→
437→          <div className="border-t border-cream-dark pt-8">
438→            <LendingDashboard
439→              agentAddress={agentAddress}
440→              humanAddress={address}
441→              isVerified={isVerified}
442→            />
443→          </div>
444→        </>
445→      )}
446→    </div>
447→  );
448→}
