  1→import { NextRequest, NextResponse } from "next/server";
  2→import {
  3→  createService,
  4→  setEnvVars,
  5→  createVolume,
  6→  createDomain,
  7→} from "@/lib/railway";
  8→import { createAgentWallet } from "@/lib/privy-server";
  9→
 10→interface DeployRequest {
 11→  agentName: string;
 12→  telegramBotToken?: string;
 13→  telegramAllowedUsers?: string;
 14→}
 15→
 16→export async function POST(req: NextRequest) {
 17→  const body: DeployRequest = await req.json();
 18→
 19→  if (!body.agentName) {
 20→    return NextResponse.json(
 21→      { error: "Missing agent name" },
 22→      { status: 400 }
 23→    );
 24→  }
 25→
 26→  try {
 27→    const projectId = process.env.RAILWAY_PROJECT_ID;
 28→    if (!projectId) {
 29→      return NextResponse.json(
 30→        { error: "RAILWAY_PROJECT_ID is not configured" },
 31→        { status: 500 }
 32→      );
 33→    }
 34→
 35→    // 0. Create Privy wallet — with EIP-7702 the EOA address IS the smart account
 36→    const { walletId, address: walletAddress } = await createAgentWallet();
 37→
 38→    // 1. Create service from GitHub repo (name = agent name for uniqueness)
 39→    const repo = "builders-garden/synthesis-hack";
 40→    const { serviceId, environmentId } = await createService(
 41→      projectId,
 42→      body.agentName,
 43→      repo,
 44→      "main",
 45→      "apps/agent"
 46→    );
 47→
 48→    // 2. Set env vars (bulk, single API call)
 49→    const setupPassword = crypto.randomUUID().replace(/-/g, "").slice(0, 32);
 50→    const envVars: Record<string, string> = {
 51→      AGENT_NAME: body.agentName,
 52→      SETUP_PASSWORD: setupPassword,
 53→      CELO_RPC_URL: process.env.CELO_RPC_URL || "https://forno.celo.org",
 54→      AGENT_WALLET_ID: walletId,
 55→      AGENT_WALLET_ADDRESS: walletAddress,
 56→    };
 57→
 58→    // Privy: pass through from server env for agent wallet signing
 59→    const privyAppId = process.env.PRIVY_APP_ID;
 60→    const privyAppSecret = process.env.PRIVY_APP_SECRET;
 61→    if (privyAppId) {
 62→      envVars.PRIVY_APP_ID = privyAppId;
 63→    }
 64→    if (privyAppSecret) {
 65→      envVars.PRIVY_APP_SECRET = privyAppSecret;
 66→    }
 67→
 68→    // Candide: pass through for gasless EIP-7702 transactions
 69→    const candideApiKey = process.env.CANDIDE_API_KEY;
 70→    if (candideApiKey) {
 71→      envVars.CANDIDE_API_KEY = candideApiKey;
 72→    }
 73→    const candidePolicyId = process.env.CANDIDE_SPONSORSHIP_POLICY_ID;
 74→    if (candidePolicyId) {
 75→      envVars.CANDIDE_SPONSORSHIP_POLICY_ID = candidePolicyId;
 76→    }
 77→
 78→    // Lending contract address
 79→    const lendingContract = process.env.LENDING_CONTRACT_ADDRESS;
 80→    if (lendingContract) {
 81→      envVars.LENDING_CONTRACT_ADDRESS = lendingContract;
 82→    }
 83→
 84→    // Telegram: use frontend values, fall back to server env vars, skip if neither
 85→    const telegramToken = body.telegramBotToken || process.env.TELEGRAM_BOT_TOKEN;
 86→    const telegramUsers = body.telegramAllowedUsers || process.env.TELEGRAM_ALLOWED_USERS;
 87→    if (telegramToken) {
 88→      envVars.TELEGRAM_BOT_TOKEN = telegramToken;
 89→    }
 90→    if (telegramUsers) {
 91→      envVars.TELEGRAM_ALLOWED_USERS = telegramUsers;
 92→    }
 93→
 94→    await setEnvVars(projectId, serviceId, environmentId, envVars);
 95→
 96→    // 3. Create persistent volume
 97→    await createVolume(projectId, serviceId, environmentId, "/data");
 98→
 99→    // 4. Generate public domain
100→    const domain = await createDomain(serviceId, environmentId);
101→
102→    // Railway auto-deploys when service is created with a linked repo + env vars set
103→
104→    return NextResponse.json({
105→      projectId,
106→      serviceId,
107→      environmentId,
108→      domain: `https://${domain}`,
109→      setupPassword,
110→      walletId,
111→      walletAddress,
112→      status: "deploying",
113→    });
114→  } catch (err) {
115→    const message = err instanceof Error ? err.message : "Deploy failed";
116→    console.error("Railway deploy error:", message);
117→    return NextResponse.json({ error: message }, { status: 500 });
118→  }
119→}
