158→export async function GET(req: NextRequest) {
159→  const sessionKey = req.nextUrl.searchParams.get("key");
160→
161→  if (!sessionKey) {
162→    return NextResponse.json(
163→      { error: "Missing key parameter" },
164→      { status: 400 }
165→    );
166→  }
167→
168→  const entry = activeSessions.get(sessionKey);
169→  if (!entry) {
170→    return NextResponse.json(
171→      { error: "Session not found or expired" },
172→      { status: 404 }
173→    );
174→  }
175→
176→  if (entry.error) {
177→    activeSessions.delete(sessionKey);
178→    return NextResponse.json({
179→      stage: "failed",
180→      error: entry.error,
181→    });
182→  }
183→
184→  if (entry.result && entry.result.status === "completed") {
185→    activeSessions.delete(sessionKey);
186→    return NextResponse.json({
187→      stage: "completed",
188→      agentId: entry.result.agentId,
189→      agentAddress: entry.result.agentAddress,
190→      txHash: entry.result.txHash,
191→    });
192→  }
193→
194→  return NextResponse.json({
195→    stage: "waiting",
196→    agentAddress: entry.agentAddress,
197→  });
198→}
