  8→
  9→async function gql<T>(query: string, variables?: Record<string, unknown>): Promise<T> {
 10→  const res = await fetch(RAILWAY_API, {
 11→    method: "POST",
 12→    headers: {
 13→      "Content-Type": "application/json",
 14→      Authorization: `Bearer ${getToken()}`,
 15→    },
 16→    body: JSON.stringify({ query, variables }),
 17→  });
 18→
 19→  const json = await res.json();
 20→  if (json.errors) {
 21→    throw new Error(json.errors.map((e: { message: string }) => e.message).join(", "));
 22→  }
 23→  return json.data as T;
 24→}
