 20→export function SelfVerification({
 21→  walletAddress,
 22→  onSuccess,
 23→}: SelfVerificationProps) {
 24→  const [session, setSession] = useState<RegistrationResponse | null>(null);
 25→  const [status, setStatus] = useState<string>("idle");
 26→  const [error, setError] = useState<string | null>(null);
 27→  const pollingRef = useRef<NodeJS.Timeout | null>(null);
 28→
 29→  // Start registration
 30→  const startRegistration = useCallback(async () => {
 31→    if (!walletAddress) return;
 32→
 33→    setStatus("registering");
 34→    setError(null);
 35→
 36→    try {
 37→      const res = await fetch("/api/agent-id/register", {
 38→        method: "POST",
 39→        headers: { "Content-Type": "application/json" },
 40→        body: JSON.stringify({
 41→          humanAddress: walletAddress,
 42→          agentName: "OpenClaw Lending Agent",
 43→        }),
 44→      });
 45→
 46→      const data = await res.json();
 47→      if (data.error) throw new Error(data.error);
 48→
 49→      setSession(data);
 50→      setStatus("waiting");
 51→    } catch (err) {
 52→      const message =
 53→        err instanceof Error ? err.message : "Registration failed";
 54→      setError(message);
 55→      setStatus("error");
 56→    }
 57→  }, [walletAddress]);
 58→
 59→  // Auto-start registration on mount
 60→  useEffect(() => {
 61→    if (walletAddress && status === "idle") {
 62→      startRegistration();
 63→    }
 64→  }, [walletAddress, status, startRegistration]);
 65→
 66→  // Poll for completion — uses server-side session tracking with rolling tokens
 67→  useEffect(() => {
 68→    if (status !== "waiting" || !session) return;
 69→
 70→    const poll = async () => {
 71→      try {
 72→        const res = await fetch(
 73→          `/api/agent-id/register?key=${encodeURIComponent(session.sessionKey)}`
 74→        );
 75→        const data = await res.json();
 76→
 77→        if (data.stage === "completed") {
 78→          setStatus("verified");
 79→          if (pollingRef.current) clearInterval(pollingRef.current);
 80→          onSuccess(data.agentAddress || session.agentAddress, data.agentId);
 81→        } else if (data.stage === "failed") {
 82→          setStatus("error");
 83→          setError(data.error || "Registration failed");
 84→          if (pollingRef.current) clearInterval(pollingRef.current);
 85→        }
 86→      } catch {
 87→        // Keep polling on transient errors
 88→      }
 89→    };
 90→
 91→    pollingRef.current = setInterval(poll, 3000);
 92→    return () => {
 93→      if (pollingRef.current) clearInterval(pollingRef.current);
 94→    };
 95→  }, [status, session, onSuccess]);
 96→
 97→  if (status === "idle" || status === "registering") {
 98→    return (
 99→      <div className="space-y-8">
100→        <div>
101→          <h3 className="font-serif text-2xl text-ink">
102→            Registering agent identity...
103→          </h3>
104→          <p className="mt-4 text-sm leading-relaxed text-ink-light">
105→            Creating a Self Agent ID linked to your wallet. This proves your
106→            agent is backed by a verified human.
107→          </p>
108→        </div>
109→        <div className="flex justify-center">
110→          <div className="h-1 w-48 overflow-hidden rounded bg-cream-dark">
111→            <div className="h-full w-1/3 animate-pulse rounded bg-ink/30" />
112→          </div>
113→        </div>
114→      </div>
115→    );
116→  }
117→
118→  if (status === "error") {
119→    return (
120→      <div className="space-y-8">
121→        <div>
122→          <h3 className="font-serif text-2xl text-ink">
123→            Registration failed.
124→          </h3>
125→          <div className="mt-4 rounded border border-red-200 bg-red-50 px-4 py-3 text-sm text-red-800">
126→            {error}
127→          </div>
128→        </div>
129→        <button
130→          onClick={() => {
131→            setStatus("idle");
132→            setSession(null);
133→            setError(null);
134→          }}
135→          className="bg-ink px-8 py-4 font-mono text-sm uppercase tracking-wider text-cream transition-opacity hover:opacity-80"
136→        >
137→          Retry
138→        </button>
139→      </div>
140→    );
141→  }
142→
143→  if (status === "verified") {
144→    return (
145→      <div className="space-y-8">
146→        <div>
147→          <h3 className="font-serif text-2xl text-ink">Identity verified.</h3>
148→          <p className="mt-4 text-sm leading-relaxed text-ink-light">
149→            Your agent has a Self Agent ID on Celo. It can now operate as a
150→            verified, human-backed agent in the lending pool.
151→          </p>
152→        </div>
153→        <div className="space-y-3 border-t border-cream-dark pt-6">
154→          <div className="flex justify-between font-mono text-sm">
155→            <span className="text-ink-lighter">Agent Address</span>
156→            <span className="text-ink">
157→              {session?.agentAddress.slice(0, 6)}...
158→              {session?.agentAddress.slice(-4)}
159→            </span>
160→          </div>
161→          <div className="flex justify-between font-mono text-sm">
162→            <span className="text-ink-lighter">Status</span>
163→            <span className="text-ink">Verified (Soulbound NFT)</span>
164→          </div>
165→          <div className="flex justify-between font-mono text-sm">
166→            <span className="text-ink-lighter">Network</span>
167→            <span className="text-ink">Celo Mainnet</span>
168→          </div>
169→        </div>
170→      </div>
171→    );
172→  }
173→
174→  // status === "waiting" — show QR code
175→  return (
176→    <div className="space-y-8">
177→      <div>
178→        <h3 className="font-serif text-2xl text-ink">
179→          Verify your identity.
