 42→async function uploadToArweave(metadata: Record<string, unknown>): Promise<string> {
 43→  const { WebUploader } = await import("@irys/web-upload");
 44→  const { WebEthereum } = await import("@irys/web-upload-ethereum");
 45→  const { ViemV2Adapter } = await import("@irys/web-upload-ethereum-viem-v2");
 46→
 47→  // eslint-disable-next-line @typescript-eslint/no-explicit-any
 48→  const provider = (window as any).ethereum;
 49→  if (!provider) throw new Error("No wallet provider found");
 50→
 51→  const [account] = await provider.request({
 52→    method: "eth_requestAccounts",
 53→  });
 54→
 55→  const walletClient = createWalletClient({
 56→    account,
 57→    chain: celo,
 58→    transport: custom(provider),
 59→  });
 60→
 61→  const publicClient = createPublicClient({
 62→    chain: celo,
 63→    transport: custom(provider),
 64→  });
 65→
 66→  // Cast to any to work around viem version mismatch between Irys and project
 67→  // eslint-disable-next-line @typescript-eslint/no-explicit-any
 68→  const irysUploader = await WebUploader(WebEthereum).withAdapter(
 69→    ViemV2Adapter(walletClient as any, { publicClient: publicClient as any })
 70→  );
 71→
 72→  const data = JSON.stringify(metadata);
 73→  const tags = [{ name: "Content-Type", value: "application/json" }];
 74→  const receipt = await irysUploader.upload(data, { tags });
 75→
 76→  return `https://gateway.irys.xyz/${receipt.id}`;
 77→}
