  1→import { createPublicClient, http, type Hex, encodeFunctionData } from "viem";
  2→import { entryPoint08Address, getUserOperationHash } from "viem/account-abstraction";
  3→import { celo } from "viem/chains";
  4→import { privateKeyToAccount } from "viem/accounts";
  5→
  6→const CELO_RPC_URL = process.env.CELO_RPC_URL || "https://forno.celo.org";
  7→const CANDIDE_API_KEY = process.env.CANDIDE_API_KEY || "";
  8→const CANDIDE_URL = CANDIDE_API_KEY
  9→  ? `https://api.candide.dev/api/v3/42220/${CANDIDE_API_KEY}`
 10→  : "https://api.candide.dev/public/v3/42220";
 11→const SPONSORSHIP_POLICY_ID = process.env.CANDIDE_SPONSORSHIP_POLICY_ID || "";
 12→
 13→// SimpleAccount v0.8 implementation (deployed on Celo, works with EP v0.8 + 7702)
 14→const SIMPLE_ACCOUNT_IMPL = "0xe6Cae83BdE06E4c305530e199D7217f42808555B" as const;
 15→
 16→const EXECUTE_ABI = [{
 17→  name: "execute",
 18→  type: "function",
 19→  inputs: [
 20→    { name: "dest", type: "address" },
 21→    { name: "value", type: "uint256" },
 22→    { name: "func", type: "bytes" },
 23→  ],
 24→  outputs: [],
 25→}] as const;
 26→
 27→const h = (v: bigint | number) => "0x" + BigInt(v).toString(16);
 28→
 29→async function candideRpc(method: string, params: any[]) {
 30→  const res = await fetch(CANDIDE_URL, {
 31→    method: "POST",
 32→    headers: { "Content-Type": "application/json" },
 33→    body: JSON.stringify({ jsonrpc: "2.0", method, params, id: Date.now() }),
 34→  });
 35→  const data = await res.json();
 36→  if (data.error) throw new Error(`${method}: ${data.error.message}`);
 37→  return data.result;
 38→}
