 40→/**
 41→ * Send a gasless EIP-7702 UserOperation using a local private key.
 42→ */
 43→async function sendUserOp(privateKey: Hex, callData: `0x${string}`) {
 44→  const owner = privateKeyToAccount(privateKey);
 45→  const walletAddress = owner.address;
 46→  const publicClient = createPublicClient({ chain: celo, transport: http(CELO_RPC_URL) });
 47→
 48→  // 1. Sign 7702 authorization
 49→  const txNonce = await publicClient.getTransactionCount({ address: walletAddress });
 50→  const auth = await owner.signAuthorization({
 51→    contractAddress: SIMPLE_ACCOUNT_IMPL,
 52→    chainId: celo.id,
 53→    nonce: txNonce,
 54→  }) as any;
 55→
 56→  const eip7702Auth = {
 57→    chainId: h(auth.chainId),
 58→    address: auth.address ?? auth.contractAddress,
 59→    nonce: h(auth.nonce),
 60→    yParity: h(auth.yParity),
 61→    r: auth.r,
 62→    s: auth.s,
 63→  };
 64→
 65→  // 2. Build base UserOp
 66→  const epNonce = await publicClient.readContract({
 67→    address: entryPoint08Address,
 68→    abi: [{ name: "getNonce", type: "function", stateMutability: "view", inputs: [{ name: "sender", type: "address" }, { name: "key", type: "uint192" }], outputs: [{ name: "", type: "uint256" }] }],
 69→    functionName: "getNonce",
 70→    args: [walletAddress, BigInt(0)],
 71→  });
 72→
 73→  const block = await publicClient.getBlock();
 74→  const baseFee = block.baseFeePerGas ?? BigInt(5000000000);
 75→  const dummySig = await owner.signMessage({ message: "7702-estimation" });
 76→
 77→  const userOp: any = {
 78→    sender: walletAddress,
 79→    nonce: h(epNonce),
 80→    callData,
 81→    callGasLimit: h(100000),
 82→    verificationGasLimit: h(500000),
 83→    preVerificationGas: h(100000),
 84→    maxFeePerGas: h(baseFee * BigInt(2)),
 85→    maxPriorityFeePerGas: h(baseFee / BigInt(5)),
 86→    signature: dummySig,
 87→    eip7702Auth,
 88→  };
 89→
 90→  // 3. Candide sponsorship
 91→  const sponsor = await candideRpc("pm_sponsorUserOperation", [
 92→    userOp, entryPoint08Address, { sponsorshipPolicyId: SPONSORSHIP_POLICY_ID },
 93→  ]);
 94→
 95→  userOp.paymaster = sponsor.paymaster;
 96→  userOp.paymasterData = sponsor.paymasterData;
 97→  userOp.paymasterVerificationGasLimit = sponsor.paymasterVerificationGasLimit;
 98→  userOp.paymasterPostOpGasLimit = sponsor.paymasterPostOpGasLimit;
 99→  if (sponsor.callGasLimit) userOp.callGasLimit = sponsor.callGasLimit;
100→  if (sponsor.verificationGasLimit) userOp.verificationGasLimit = sponsor.verificationGasLimit;
101→  if (sponsor.preVerificationGas) userOp.preVerificationGas = sponsor.preVerificationGas;
102→  if (sponsor.maxFeePerGas) userOp.maxFeePerGas = sponsor.maxFeePerGas;
103→  if (sponsor.maxPriorityFeePerGas) userOp.maxPriorityFeePerGas = sponsor.maxPriorityFeePerGas;
104→
105→  // 4. Compute hash and sign with raw secp256k1
106→  const opHash = getUserOperationHash({
107→    userOperation: {
108→      sender: walletAddress,
109→      nonce: BigInt(userOp.nonce),
110→      callData: userOp.callData,
111→      callGasLimit: BigInt(userOp.callGasLimit),
112→      verificationGasLimit: BigInt(userOp.verificationGasLimit),
113→      preVerificationGas: BigInt(userOp.preVerificationGas),
114→      maxFeePerGas: BigInt(userOp.maxFeePerGas),
115→      maxPriorityFeePerGas: BigInt(userOp.maxPriorityFeePerGas),
116→      paymaster: userOp.paymaster,
117→      paymasterData: userOp.paymasterData || "0x",
118→      paymasterVerificationGasLimit: BigInt(userOp.paymasterVerificationGasLimit || "0x0"),
119→      paymasterPostOpGasLimit: BigInt(userOp.paymasterPostOpGasLimit || "0x0"),
120→      signature: "0x",
121→    },
122→    entryPointAddress: entryPoint08Address,
123→    entryPointVersion: "0.8",
124→    chainId: celo.id,
125→  });
126→
127→  // Raw ECDSA sign (no EIP-191 prefix — SimpleAccount v0.8 uses raw ecrecover)
128→  const sig = await owner.sign({ hash: opHash });
129→  userOp.signature = sig;
130→
131→  // 5. Send
132→  return await candideRpc("eth_sendUserOperation", [userOp, entryPoint08Address]);
133→}
