135→// USDC on Celo
136→const USDC_ADDRESS = "0xcebA9300f2b948710d2653dD7B07f33A8B32118C" as const;
137→const ERC20_ABI = [
138→  {
139→    name: "transfer",
140→    type: "function",
141→    inputs: [
142→      { name: "to", type: "address" },
143→      { name: "amount", type: "uint256" },
144→    ],
145→    outputs: [{ name: "", type: "bool" }],
146→  },
147→  {
148→    name: "approve",
149→    type: "function",
150→    inputs: [
151→      { name: "spender", type: "address" },
152→      { name: "amount", type: "uint256" },
153→    ],
154→    outputs: [{ name: "", type: "bool" }],
155→  },
156→  {
157→    name: "balanceOf",
158→    type: "function",
159→    inputs: [{ name: "account", type: "address" }],
160→    outputs: [{ name: "", type: "uint256" }],
161→  },
162→] as const;
163→
164→export async function sendGaslessUSDCTransfer(
165→  privateKey: Hex,
166→  to: `0x${string}`,
167→  amount: bigint
168→) {
169→  const callData = encodeFunctionData({
170→    abi: EXECUTE_ABI,
171→    functionName: "execute",
172→    args: [USDC_ADDRESS, BigInt(0), encodeFunctionData({
173→      abi: ERC20_ABI,
174→      functionName: "transfer",
175→      args: [to, amount],
176→    })],
177→  });
178→  return sendUserOp(privateKey, callData as `0x${string}`);
179→}
180→
181→export async function sendGaslessContractCall(
182→  privateKey: Hex,
183→  to: `0x${string}`,
184→  data: `0x${string}`
185→) {
186→  const callData = encodeFunctionData({
187→    abi: EXECUTE_ABI,
188→    functionName: "execute",
189→    args: [to, BigInt(0), data],
190→  });
191→  return sendUserOp(privateKey, callData as `0x${string}`);
192→}
